PREFIX wdt: <http://www.wikidata.org/prop/direct/>
PREFIX wd: <http://www.wikidata.org/entity/>
SELECT(COUNT(DISTINCT ?driver) AS ?count) WHERE {
  VALUES ?race {
    wd:Q19704270 wd:Q23045166
  }
  ?race wdt:P870 ?qualifyingSession .
  ?qualifyingSession wdt:P1002 ?driver .
  ?driver wdt:P31 wd:Q5630 .
}
GROUP BY ?race
ORDER BY ASC(?count)
LIMIT 2
